  let subtotal = evaluate(`${baseLabor} * ${complexityMultiplier}`);
  if (includeSafetyMargin) {
    subtotal = evaluate(`${subtotal} * 1.15`);
  }
  const totalFee = evaluate(`${subtotal} + ${operatingExpenses}`);
  const bufferAmount = evaluate(
    `${totalFee} - ${baseLabor} - ${operatingExpenses}`
  );
  const taxRate = taxBufferPct / 100;
  const taxSetAside = evaluate(
    `(${totalFee} - ${operatingExpenses}) * ${taxRate}`
  );
  const takeHomePay = evaluate(
    `${totalFee} - ${taxSetAside} - ${operatingExpenses}`
  );
  const businessFund = operatingExpenses;
  const netProfitPct = totalFee > 0 ? evaluate(`(${takeHomePay} / ${totalFee}) * 100`) : 0;
  let vibeStatus;
